import { chromium } from "playwright";
import path from "path";

const baseUrl = process.env.PREVIEW_URL ?? "http://localhost:3000";
const outputDir = path.resolve("..", "screenshots");

const protectedState = {
  origins: [
    {
      origin: baseUrl,
      localStorage: [
        { name: "internflow_token", value: "preview-token" },
        {
          name: "internflow_user",
          value: JSON.stringify({
            id: "preview-user",
            email: "admin@lumentix.in",
            role: "Admin"
          })
        }
      ]
    }
  ],
  cookies: [
    {
      name: "internflow_token",
      value: "preview-token",
      url: baseUrl,
      httpOnly: false,
      secure: false,
      sameSite: "Lax",
      expires: Math.floor(Date.now() / 1000) + 3600
    }
  ]
};

const pages = [
  { name: "01-login", url: "/login", auth: false },
  { name: "02-dashboard", url: "/dashboard", auth: true },
  { name: "03-interns", url: "/interns", auth: true },
  { name: "04-add-intern", url: "/interns/add", auth: true },
  { name: "05-documents", url: "/documents/generate", auth: true },
  { name: "06-verify", url: "/verify/LTX-20260416-0001", auth: false }
];

const browser = await chromium.launch({
  channel: "chrome",
  headless: true
});

for (const item of pages) {
  const context = await browser.newContext({
    viewport: { width: 1440, height: 1000 },
    deviceScaleFactor: 1,
    storageState: item.auth ? protectedState : undefined
  });

  const page = await context.newPage();
  await page.goto(`${baseUrl}${item.url}`, {
    waitUntil: "domcontentloaded",
    timeout: 30000
  });
  await page.waitForTimeout(1800);
  console.log(`${item.name}: ${page.url()}`);
  await page.screenshot({
    path: path.join(outputDir, `${item.name}.png`),
    fullPage: true
  });
  await context.close();
}

await browser.close();
